// Determine which topics were approved based on action parameter
const action = $('Webhook - Topic Approval').first().json.query.action;
const sheetData = $json;

const approvedTopics = [];

if (action === 'approve_all') {
  approvedTopics.push(
    { topicKey: 'topic_1', topicText: sheetData.topic_1 },
    { topicKey: 'topic_2', topicText: sheetData.topic_2 },
    { topicKey: 'topic_3', topicText: sheetData.topic_3 }
  );
} else if (action === 'approve_12') {
  approvedTopics.push(
    { topicKey: 'topic_1', topicText: sheetData.topic_1 },
    { topicKey: 'topic_2', topicText: sheetData.topic_2 }
  );
} else if (action === 'approve_13') {
  approvedTopics.push(
    { topicKey: 'topic_1', topicText: sheetData.topic_1 },
    { topicKey: 'topic_3', topicText: sheetData.topic_3 }
  );
} else if (action === 'approve_23') {
  approvedTopics.push(
    { topicKey: 'topic_2', topicText: sheetData.topic_2 },
    { topicKey: 'topic_3', topicText: sheetData.topic_3 }
  );
} else if (action === 'approve_1') {
  approvedTopics.push(
    { topicKey: 'topic_1', topicText: sheetData.topic_1 }
  );
} else if (action === 'approve_2') {
  approvedTopics.push(
    { topicKey: 'topic_2', topicText: sheetData.topic_2 }
  );
} else if (action === 'approve_3') {
  approvedTopics.push(
    { topicKey: 'topic_3', topicText: sheetData.topic_3 }
  );
}

// Return array of approved topics with context
return approvedTopics.map(topic => ({
  json: {
    topicKey: topic.topicKey,
    topicText: topic.topicText,
    weekOf: sheetData.week_of,
    businessUpdates: sheetData.business_updates || 'No updates available'
  }
}));

// Extract post text from OpenAI response
const openaiResponse = $('OpenAI - Generate Post Text').first().json;
const postText = openaiResponse.choices?.[0]?.message?.content || openaiResponse.message?.content || 'Error generating post';

// Extract image URL from kie.ai response
// NOTE: User must update this based on actual kie.ai API response format
const kieaiResponse = $json;
const imageUrl = kieaiResponse.image_url || kieaiResponse.url || kieaiResponse.data?.url || 'PLACEHOLDER_IMAGE_URL';

// Get topic context from loop
const topicKey = $('Code - Determine Approved Topics').item.json.topicKey;
const weekOf = $('Code - Determine Approved Topics').item.json.weekOf;

return {
  json: {
    topicKey: topicKey,
    weekOf: weekOf,
    postText: postText,
    imageUrl: imageUrl,
    generatedAt: new Date().toISOString()
  }
};

// Build approval email body with all generated posts
const data = $json;
const weekOf = data.week_of;

// Collect all posts
const posts = [];
for (let i = 1; i <= 3; i++) {
  const topicKey = `topic_${i}`;
  if (data[`${topicKey}_post`]) {
    posts.push({
      number: i,
      topic: data[topicKey],
      post: data[`${topicKey}_post`],
      imageUrl: data[`${topicKey}_image_url`] || 'No image generated'
    });
  }
}

// Build email body
let emailBody = `Hi there,\n\nThe social media content for the week of ${weekOf} has been generated and is ready for your review.\n\n`;
emailBody += `==================================================\n\n`;

for (const post of posts) {
  emailBody += `POST ${post.number} - ${post.topic}\n`;
  emailBody += `${'-'.repeat(50)}\n`;
  emailBody += `${post.post}\n\n`;
  emailBody += `Image: ${post.imageUrl}\n`;
  emailBody += `\n==================================================\n\n`;
}

emailBody += `\nPlease review the posts and images above, then approve by clicking one of the links below:\n\n`;
emailBody += `Approve All Posts: PLACEHOLDER_WORKFLOW3_WEBHOOK_URL?week_of=${weekOf}&action=approve_all\n\n`;
emailBody += `Edit Required: Access the Google Sheet to make manual edits: PLACEHOLDER_SHEET_URL\n\n`;
emailBody += `Reject All: Reply to this email to regenerate content\n\n`;
emailBody += `Note: You can view the images by clicking the URLs above.\n\n`;
emailBody += `Once approved, posts will be scheduled for Monday, Wednesday, and Friday of the following week at 10:00 AM.`;

return {
  json: {
    recipientEmail: 'PLACEHOLDER_APPROVER_EMAIL',
    emailSubject: `Social Media Content Ready for Approval - Week of ${weekOf}`,
    emailBody: emailBody,
    weekOf: weekOf
  }
};

// Prepare context for OpenAI topic generation
const currentDate = new Date();
const weekOf = currentDate.toISOString().split('T')[0];

// Get latest business update from sheet
const items = $input.all();
let businessUpdates = 'No updates provided this week';

if (items.length > 0) {
  // Get the most recent update (assuming sorted by date)
  const latestUpdate = items[items.length - 1].json;
  businessUpdates = latestUpdate['Update Description'] || latestUpdate.updates || latestUpdate.description || 'No updates available';
}

// Calculate current month for seasonal/awareness content
const month = currentDate.getMonth();
const seasonalEvents = {
  0: "New Year wellness tips, winter safety for seniors, flu prevention",
  1: "Heart Health Month, Valentine's Day connections for seniors",
  2: "Brain Injury Awareness Month, spring safety tips",
  3: "Parkinson's Awareness Month, spring allergies for seniors",
  4: "Older Americans Month, Mental Health Awareness Month",
  5: "Alzheimer's and Brain Awareness Month, summer safety for seniors",
  6: "Summer activities for seniors, heat safety, staying active",
  7: "Back-to-school for grandparents, late summer wellness",
  8: "World Alzheimer's Month, fall prevention, National Family Caregiver Month (Nov prep)",
  9: "Fall safety, breast cancer awareness, National Family Caregiver Month (Nov prep)",
  10: "National Family Caregivers Month, diabetes awareness, Thanksgiving safety",
  11: "Holiday safety for seniors, winter depression prevention, end-of-year reflection"
};

const context = {
  weekOf: weekOf,
  businessUpdates: businessUpdates,
  seasonalTheme: seasonalEvents[month],
  currentMonth: currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  companyName: 'Right At Home Winnipeg',
  targetAudience: 'older adults, their families, and caregivers in Winnipeg, Manitoba',
  services: 'in-home senior care, companionship, personal care, dementia care, Alzheimer\'s care, respite care',
  brandVoice: 'warm, compassionate, professional, dignity-focused'
};

return [{ json: context }];

// Parse OpenAI response and extract topics
const openaiResponse = $json;
const messageContent = openaiResponse.choices?.[0]?.message?.content || openaiResponse.message?.content || '{}';

// Remove markdown code blocks if present
const jsonString = messageContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let topics;
try {
  topics = JSON.parse(jsonString);
} catch (error) {
  // Fallback if parsing fails
  topics = {
    topic1: 'Error parsing AI response - please check workflow execution',
    topic2: 'Error parsing AI response - please check workflow execution',
    topic3: 'Error parsing AI response - please check workflow execution'
  };
}

// Get context from previous node
const context = $('Code - Prepare AI Context').first().json;

return {
  json: {
    week_of: context.weekOf,
    business_updates: context.businessUpdates,
    topic_1: topics.topic1 || 'No topic generated',
    topic_2: topics.topic2 || 'No topic generated',
    topic_3: topics.topic3 || 'No topic generated',
    generation_timestamp: new Date().toISOString(),
    topic_1_approved: false,
    topic_2_approved: false,
    topic_3_approved: false,
    completion_status: 'Topics Generated - Awaiting Approval'
  }
};

// Format approval email with webhook links
const data = $json;
const weekOf = data.week_of;
const topic1 = data.topic_1;
const topic2 = data.topic_2;
const topic3 = data.topic_3;
const businessUpdates = data.business_updates;

// Webhook base URL - user must update after deploying Workflow 2
const webhookBaseUrl = 'PLACEHOLDER_WORKFLOW2_WEBHOOK_URL';

// Build email body
let emailBody = `Hi there,\n\n`;
emailBody += `The AI has generated 3 social media topic ideas for the week of ${weekOf}. Please review and approve the topics you'd like to proceed with.\n\n`;
emailBody += `==================================================\n\n`;

emailBody += `TOPIC 1 - BUSINESS UPDATE\n`;
emailBody += `${topic1}\n\n`;

emailBody += `TOPIC 2 - MARKETING/SERVICE\n`;
emailBody += `${topic2}\n\n`;

emailBody += `TOPIC 3 - AUDIENCE-RELEVANT\n`;
emailBody += `${topic3}\n\n`;

emailBody += `==================================================\n\n`;

emailBody += `GENERATED FROM:\n`;
emailBody += `Business Updates: ${businessUpdates}\n\n`;

emailBody += `==================================================\n\n`;
emailBody += `APPROVAL OPTIONS:\n\n`;

emailBody += `✓ Approve All 3 Topics:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_all\n\n`;

emailBody += `✓ Approve Topics 1 & 2 Only:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_12\n\n`;

emailBody += `✓ Approve Topics 1 & 3 Only:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_13\n\n`;

emailBody += `✓ Approve Topics 2 & 3 Only:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_23\n\n`;

emailBody += `✓ Approve Only Topic 1:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_1\n\n`;

emailBody += `✓ Approve Only Topic 2:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_2\n\n`;

emailBody += `✓ Approve Only Topic 3:\n`;
emailBody += `${webhookBaseUrl}?week_of=${weekOf}&action=approve_3\n\n`;

emailBody += `==================================================\n\n`;

emailBody += `Once you click an approval link, the system will automatically:\n`;
emailBody += `1. Generate full social media posts with hashtags for approved topics\n`;
emailBody += `2. Create custom 1080x1080 images for each post\n`;
emailBody += `3. Send you another email for final approval\n\n`;

emailBody += `If you need different topics, reply to this email and the team will regenerate.\n\n`;

emailBody += `State Tracking Sheet: PLACEHOLDER_STATE_SHEET_URL`;

return {
  json: {
    recipientEmail: 'PLACEHOLDER_APPROVER_EMAIL',
    emailSubject: `📝 Weekly Social Media Topics for Approval - Week of ${weekOf}`,
    emailBody: emailBody,
    weekOf: weekOf
  }
};

// Calculate posting dates: Monday, Wednesday, Friday of the following week
const sheetData = $json;
const weekOf = new Date(sheetData.week_of);

// Find next Monday after week_of
const dayOfWeek = weekOf.getDay();
const daysUntilMonday = (1 - dayOfWeek + 7) % 7 || 7;
const monday = new Date(weekOf);
monday.setDate(weekOf.getDate() + daysUntilMonday);

// Calculate Wednesday and Friday
const wednesday = new Date(monday);
wednesday.setDate(monday.getDate() + 2);

const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);

// Set posting time to 10:00 AM
[monday, wednesday, friday].forEach(date => {
  date.setHours(10, 0, 0, 0);
});

// Build post objects for each day
const posts = [];

if (sheetData.topic_1_post) {
  posts.push({
    topicKey: 'topic_1',
    topic: sheetData.topic_1,
    postText: sheetData.topic_1_post,
    imageUrl: sheetData.topic_1_image_url,
    postDate: monday.toISOString(),
    unixTimestamp: Math.floor(monday.getTime() / 1000),
    dayLabel: 'Monday',
    weekOf: sheetData.week_of
  });
}

if (sheetData.topic_2_post) {
  posts.push({
    topicKey: 'topic_2',
    topic: sheetData.topic_2,
    postText: sheetData.topic_2_post,
    imageUrl: sheetData.topic_2_image_url,
    postDate: wednesday.toISOString(),
    unixTimestamp: Math.floor(wednesday.getTime() / 1000),
    dayLabel: 'Wednesday',
    weekOf: sheetData.week_of
  });
}

if (sheetData.topic_3_post) {
  posts.push({
    topicKey: 'topic_3',
    topic: sheetData.topic_3,
    postText: sheetData.topic_3_post,
    imageUrl: sheetData.topic_3_image_url,
    postDate: friday.toISOString(),
    unixTimestamp: Math.floor(friday.getTime() / 1000),
    dayLabel: 'Friday',
    weekOf: sheetData.week_of
  });
}

return posts.map(post => ({ json: post }));

// Prepare data for sheet update
const topicKey = $('Code - Calculate Posting Dates').item.json.topicKey;
const weekOf = $('Code - Calculate Posting Dates').item.json.weekOf;
const postDate = $('Code - Calculate Posting Dates').item.json.postDate;
const dayLabel = $('Code - Calculate Posting Dates').item.json.dayLabel;

// Check if Facebook and Instagram scheduling succeeded
const facebookResponse = $('HTTP Request - Schedule Facebook Post').first().json;
const instagramResponse = $json;

const facebookSuccess = !facebookResponse.error;
const instagramSuccess = !instagramResponse.error;

let status = 'Scheduled';
if (!facebookSuccess || !instagramSuccess) {
  status = 'Partially Scheduled';
}
if (!facebookSuccess && !instagramSuccess) {
  status = 'Scheduling Failed';
}

return {
  json: {
    weekOf: weekOf,
    topicKey: topicKey,
    scheduled: facebookSuccess && instagramSuccess,
    postDate: postDate,
    dayLabel: dayLabel,
    status: status,
    facebookPostId: facebookResponse.id || 'N/A',
    instagramMediaId: instagramResponse.id || 'N/A'
  }
};

// Build confirmation email with scheduling details
const data = $json;
const weekOf = data.week_of;

// Collect scheduled posts
const scheduledPosts = [];
for (let i = 1; i <= 3; i++) {
  const topicKey = `topic_${i}`;
  if (data[`${topicKey}_post_date`]) {
    const postDate = new Date(data[`${topicKey}_post_date`]);
    const dateStr = postDate.toLocaleDateString('en-US', {
      weekday: 'long',
      month: 'long',
      day: 'numeric',
      year: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
      timeZoneName: 'short'
    });

    scheduledPosts.push({
      number: i,
      topic: data[topicKey],
      postDate: dateStr,
      status: data[`${topicKey}_status`] || 'Scheduled',
      scheduled: data[`${topicKey}_scheduled`]
    });
  }
}

// Build email body
let emailBody = `Hi there,\n\nYour social media posts for the week of ${weekOf} have been successfully scheduled!\n\n`;
emailBody += `==================================================\n\n`;

let allSuccess = true;
for (const post of scheduledPosts) {
  const statusIcon = post.scheduled ? '✓' : '✗';
  emailBody += `POST ${post.number}: ${post.topic}\n`;
  emailBody += `Status: ${statusIcon} ${post.status}\n`;
  emailBody += `Scheduled for: ${post.postDate}\n`;
  emailBody += `Platforms: Facebook ${post.scheduled ? '✓' : '✗'} | Instagram ${post.scheduled ? '✓' : '✗'}\n`;
  emailBody += `\n==================================================\n\n`;

  if (!post.scheduled) {
    allSuccess = false;
  }
}

if (allSuccess) {
  emailBody += `\nAll posts have been successfully scheduled to both Facebook and Instagram.\n\n`;
} else {
  emailBody += `\n⚠️ WARNING: Some posts failed to schedule. Please check your n8n workflow execution logs for details.\n\n`;
}

emailBody += `You can monitor and manage your scheduled posts in:\n`;
emailBody += `- Meta Business Suite: https://business.facebook.com/latest/posts\n`;
emailBody += `- n8n State Sheet: PLACEHOLDER_SHEET_URL\n\n`;
emailBody += `The workflow will run again next Sunday to generate topics for the following week.\n\n`;
emailBody += `Note: Posts can be edited or cancelled in Meta Business Suite if needed before they go live.`;

return {
  json: {
    recipientEmail: 'PLACEHOLDER_APPROVER_EMAIL',
    emailSubject: allSuccess 
      ? `✓ Social Media Posts Scheduled - Week of ${weekOf}`
      : `⚠️ Social Media Scheduling Partially Completed - Week of ${weekOf}`,
    emailBody: emailBody,
    weekOf: weekOf,
    allSuccess: allSuccess
  }
};
